import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, X, Lock, Calendar, Check, Users } from 'lucide-react';
import { Session, View } from '../../types';
import { mockDb, addSession, mockUsers, mockTimestamp } from '../../services/mockData';

interface AgendaViewProps {
  userId?: string;
  userPlan?: string;
  setRewardQueue: (rewards: any) => void;
  setCurrentView?: (view: View) => void;
  isTrainer?: boolean;
}

// Helper to get the start of the week (Monday)
const getStartOfWeek = (date: Date) => {
    const d = new Date(date);
    d.setHours(0, 0, 0, 0);
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1); // adjust when day is sunday
    return new Date(d.setDate(diff));
};

const AgendaView: React.FC<AgendaViewProps> = ({ userId, userPlan, setRewardQueue, setCurrentView, isTrainer }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [modal, setModal] = useState<{ 
      type: string; 
      sessionTime: string; 
      sessionDay: number | null, 
      message?: string, 
      sessionToReplace?: Session, 
      clientName?: string,
      isRecurring?: boolean 
  }>({ type: 'none', sessionTime: '', sessionDay: null });

  const [bookedSessions, setBookedSessions] = useState<(Session & { clientName?: string })[]>([]);

  useEffect(() => {
    if (isTrainer) {
        // Collect ALL sessions from ALL users
        const allSessions: (Session & { clientName?: string })[] = [];
        Object.keys(mockDb).forEach(uid => {
            if (uid === 'trainer01') return;
            const userSessions = mockDb[uid].sessions || [];
            const userProfile = mockUsers.find(u => u.id === uid);
            const userName = userProfile ? (userProfile.displayName || userProfile.username) : 'Atleta';

            userSessions.forEach(s => {
                allSessions.push({ ...s, clientName: userName });
            });
        });
        setBookedSessions(allSessions);
    } else if (userId && mockDb[userId]) {
      // Safe access check for sessions for a single user
      const userSessions = mockDb[userId].sessions || [];
      setBookedSessions([...userSessions]);
    }
  }, [userId, isTrainer, modal.type]); // Refresh when modal state changes (e.g. after booking)

  // Logic to determine if user can book an evaluation (No plan + 0 sessions)
  const isEligibleForEvaluation = !isTrainer && (!userPlan || userPlan === 'Sin Plan') && bookedSessions.length === 0;

  // Check if user has a valid plan (always true for trainer viewing agenda, or if eligible for eval)
  const hasPlan = isTrainer || (!!userPlan && userPlan !== 'Sin Plan');
  const canBook = hasPlan || isEligibleForEvaluation;

  const getGoogleCalendarUrl = (sessionDate: Date, sessionTime: string, isRecurring: boolean = false) => {
    const [hour, minute] = sessionTime.split(':');
    const startDateTime = new Date(sessionDate.getFullYear(), sessionDate.getMonth(), sessionDate.getDate(), parseInt(hour), parseInt(minute));
    const endDateTime = new Date(startDateTime);
    endDateTime.setHours(startDateTime.getHours() + 1);
    const formatDateTime = (date: Date) => date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
    const title = encodeURIComponent("Sesión de Entrenamiento Tommybox");
    const description = encodeURIComponent(`Sesión de entrenamiento personal agendada.`);

    let url = `https://www.google.com/calendar/render?action=TEMPLATE&text=${title}&dates=${formatDateTime(startDateTime)}/${formatDateTime(endDateTime)}&details=${description}`;

    if (isRecurring) {
        // RRULE:FREQ=WEEKLY;UNTIL=YYYYMMDDTHHMMSSZ
        url += `&recur=RRULE:FREQ=WEEKLY`;
    }

    return url;
  };

  const getIcsUrl = (sessionDate: Date, sessionTime: string, isRecurring: boolean = false) => {
    const [hour, minute] = sessionTime.split(':');
    const startDateTime = new Date(sessionDate.getFullYear(), sessionDate.getMonth(), sessionDate.getDate(), parseInt(hour), parseInt(minute));
    const endDateTime = new Date(startDateTime);
    endDateTime.setHours(startDateTime.getHours() + 1);
    const formatDateIcs = (date: Date) => date.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, '');

    let icsContent = `BEGIN:VCALENDAR\nVERSION:2.0\nPRODID:-//Tommybox//NONSGML v1.0//ES\nBEGIN:VEVENT\nUID:${new Date().getTime()}@tomybox.com\nDTSTAMP:${formatDateIcs(new Date())}\nDTSTART:${formatDateIcs(startDateTime)}\nDTEND:${formatDateIcs(endDateTime)}\nSUMMARY:Sesión de Entrenamiento Tommybox\nDESCRIPTION:Sesión de entrenamiento personal agendada.`;

    if (isRecurring) {
        icsContent += `\nRRULE:FREQ=WEEKLY`;
    }

    icsContent += `\nEND:VEVENT\nEND:VCALENDAR`;
    return `data:text/calendar;charset=utf8,${encodeURIComponent(icsContent)}`;
  };

  const days = ['Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'];
  const times = ['08:00', '09:00', '10:00', '11:00', '12:00', '13:00', '16:00', '17:00', '18:00', '19:00', '20:00'];

  // Logic for prev/next week
  const changeWeek = (direction: number) => {
      const newDate = new Date(currentDate);
      newDate.setDate(newDate.getDate() + (direction * 7));
      setCurrentDate(newDate);
  };

  const startOfWeek = getStartOfWeek(currentDate);

  // Logic for booking
  const handleSlotClick = (dayIndex: number, time: string) => {
      // Calculate date of slot
      const slotDate = new Date(startOfWeek);
      slotDate.setDate(slotDate.getDate() + dayIndex);
      const dateStr = slotDate.toISOString().split('T')[0];

      // Check if past
      if (slotDate < new Date() && slotDate.getDate() !== new Date().getDate()) return;

      // Check existing booking for user
      const existingSession = bookedSessions.find(s => s.date === dateStr && s.time === time);

      if (isTrainer) {
           // Trainer sees details
           if (existingSession) {
               alert(`Sesión agendada con: ${existingSession.clientName}`);
           }
           return; // Trainer doesn't book here
      }

      if (existingSession) {
           alert("Ya tienes una sesión agendada en este horario.");
           return;
      }

      if (!canBook) {
           setModal({
               type: 'no-plan',
               sessionTime: time,
               sessionDay: dayIndex,
               message: "Necesitas un plan activo para agendar sesiones."
           });
           return;
      }

      setModal({
          type: 'confirm',
          sessionTime: time,
          sessionDay: dayIndex,
          isRecurring: false
      });
  };

  const confirmBooking = () => {
      if (userId && modal.sessionDay !== null) {
           const slotDate = new Date(startOfWeek);
           slotDate.setDate(slotDate.getDate() + modal.sessionDay);
           const dateStr = slotDate.toISOString().split('T')[0];

           const newSession: Session = {
               id: `sess_${Date.now()}`,
               date: dateStr,
               time: modal.sessionTime,
               timestamp: mockTimestamp(new Date())
           };

           const rewards = addSession(userId, newSession);
           if (rewards) setRewardQueue(prev => [...prev, rewards]);

           // Force local refresh (although useEffect handles most)
           if (mockDb[userId]) {
              setBookedSessions(mockDb[userId].sessions || []);
           }

           setModal({ ...modal, type: 'success' });
      }
  };

  // Render logic
  const renderCell = (dayIndex: number, time: string) => {
      const slotDate = new Date(startOfWeek);
      slotDate.setDate(slotDate.getDate() + dayIndex);
      const dateStr = slotDate.toISOString().split('T')[0];

      const isPast = slotDate < new Date() && slotDate.getDate() !== new Date().getDate();

      // Find bookings in this slot
      const myBooking = !isTrainer && bookedSessions.find(s => s.date === dateStr && s.time === time);
      const trainerBooking = isTrainer && bookedSessions.find(s => s.date === dateStr && s.time === time);

      let cellClass = "border border-gray-100 p-2 h-14 sm:h-20 transition-all cursor-pointer relative flex flex-col items-center justify-center ";

      if (isPast) {
          cellClass += "bg-gray-100 text-gray-300 cursor-not-allowed";
      } else if (myBooking) {
          cellClass += "bg-blue-100 border-blue-200 hover:bg-blue-200";
      } else if (trainerBooking) {
          cellClass += "bg-purple-100 border-purple-200 hover:bg-purple-200";
      } else {
          cellClass += "hover:bg-gray-50 bg-white";
      }

      return (
          <div 
              key={`${dayIndex}-${time}`} 
              className={cellClass}
              onClick={() => !isPast && handleSlotClick(dayIndex, time)}
          >
              {myBooking && (
                  <div className="flex flex-col items-center animate-scale-up">
                      <Check className="text-blue-600 mb-1" size={16} />
                      <span className="text-[10px] font-bold text-blue-700 hidden sm:inline">Tu Sesión</span>
                  </div>
              )}
              {trainerBooking && (
                  <div className="flex flex-col items-center animate-scale-up w-full overflow-hidden px-1">
                      <Users className="text-purple-600 mb-1" size={16} />
                      <span className="text-[9px] sm:text-[10px] font-bold text-purple-700 truncate w-full text-center">
                          {trainerBooking.clientName}
                      </span>
                  </div>
              )}
              {!myBooking && !trainerBooking && !isPast && (
                  <div className="opacity-0 hover:opacity-100 transition-opacity">
                      <div className="w-2 h-2 bg-blue-400 rounded-full"></div>
                  </div>
              )}
          </div>
      );
  };

  return (
    <section className="container mx-auto px-2 sm:px-4 py-8 max-w-5xl">
       {/* Header */}
       <div className="flex flex-col md:flex-row justify-between items-center mb-6 bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
           <div className="mb-4 md:mb-0">
               <h2 className="text-2xl font-black text-gray-900 flex items-center gap-2">
                   <Calendar className="text-blue-600" /> Agenda Semanal
               </h2>
               <p className="text-gray-500 text-sm">
                   {isTrainer ? 'Gestiona las sesiones de todos los atletas' : 'Reserva tus horas de entrenamiento'}
               </p>
           </div>

           <div className="flex items-center gap-4 bg-gray-50 p-2 rounded-xl">
               <button onClick={() => changeWeek(-1)} className="p-2 hover:bg-white hover:shadow-md rounded-lg transition-all text-gray-600">
                   <ChevronLeft size={20} />
               </button>
               <span className="text-sm font-bold w-32 text-center">
                   {startOfWeek.toLocaleDateString('es-ES', { month: 'short', day: 'numeric' })} - {(() => {
                       const end = new Date(startOfWeek);
                       end.setDate(end.getDate() + 5);
                       return end.toLocaleDateString('es-ES', { month: 'short', day: 'numeric' });
                   })()}
               </span>
               <button onClick={() => changeWeek(1)} className="p-2 hover:bg-white hover:shadow-md rounded-lg transition-all text-gray-600">
                   <ChevronRight size={20} />
               </button>
           </div>
       </div>

       {/* Grid */}
       <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
           {/* Days Header */}
           <div className="grid grid-cols-7 border-b border-gray-100 bg-gray-50">
               <div className="p-2 sm:p-4 text-center border-r border-gray-100 flex items-center justify-center">
                   <span className="text-xs font-bold text-gray-400">HORA</span>
               </div>
               {days.map((day, index) => {
                   const date = new Date(startOfWeek);
                   date.setDate(date.getDate() + index);
                   const isToday = new Date().toDateString() === date.toDateString();

                   return (
                       <div key={day} className={`p-2 sm:p-4 text-center border-r border-gray-100 last:border-r-0 ${isToday ? 'bg-blue-50' : ''}`}>
                           <p className={`text-[10px] sm:text-xs font-bold uppercase mb-1 ${isToday ? 'text-blue-600' : 'text-gray-400'}`}>{day}</p>
                           <p className={`text-sm sm:text-lg font-black ${isToday ? 'text-blue-700' : 'text-gray-800'}`}>
                               {date.getDate()}
                           </p>
                       </div>
                   );
               })}
           </div>

           {/* Time Slots */}
           <div className="divide-y divide-gray-100">
               {times.map(time => (
                   <div key={time} className="grid grid-cols-7">
                       <div className="p-2 sm:p-4 text-center border-r border-gray-100 flex items-center justify-center bg-gray-50/50">
                           <span className="text-xs font-bold text-gray-500">{time}</span>
                       </div>
                       {days.map((_, dayIndex) => renderCell(dayIndex, time))}
                   </div>
               ))}
           </div>
       </div>

       {/* Modals */}
       {modal.type !== 'none' && (
           <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fade-in">
               <div className="bg-white rounded-3xl p-8 max-w-sm w-full shadow-2xl relative">
                   <button 
                        onClick={() => setModal({ ...modal, type: 'none' })}
                        className="absolute top-4 right-4 text-gray-400 hover:text-gray-600"
                   >
                       <X size={20} />
                   </button>

                   {modal.type === 'no-plan' && (
                       <div className="text-center">
                           <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-500">
                               <Lock size={32} />
                           </div>
                           <h3 className="text-xl font-bold text-gray-900 mb-2">Acceso Restringido</h3>
                           <p className="text-gray-500 mb-6">{modal.message}</p>
                           <button 
                               onClick={() => { setModal({ ...modal, type: 'none' }); if (setCurrentView) setCurrentView('plans'); }}
                               className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700"
                           >
                               Ver Planes
                           </button>
                       </div>
                   )}

                   {modal.type === 'confirm' && (
                       <div className="text-center">
                           <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600">
                               <Calendar size={32} />
                           </div>
                           <h3 className="text-xl font-bold text-gray-900 mb-2">Confirmar Reserva</h3>
                           <p className="text-gray-500 mb-6">
                               ¿Agendar sesión para el <br/>
                               <span className="font-bold text-gray-900">
                                   {days[modal.sessionDay!]} a las {modal.sessionTime}
                               </span>?
                           </p>

                           <div className="flex gap-3">
                               <button 
                                   onClick={() => setModal({ ...modal, type: 'none' })}
                                   className="flex-1 py-3 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200"
                               >
                                   Cancelar
                               </button>
                               <button 
                                   onClick={confirmBooking}
                                   className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700"
                               >
                                   Confirmar
                               </button>
                           </div>
                       </div>
                   )}

                   {modal.type === 'success' && (
                       <div className="text-center">
                           <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4 text-green-600 animate-scale-up">
                               <Check size={32} strokeWidth={4} />
                           </div>
                           <h3 className="text-xl font-bold text-gray-900 mb-2">¡Reserva Exitosa!</h3>
                           <p className="text-gray-500 mb-6">Tu sesión ha sido agendada correctamente.</p>

                           <div className="space-y-3">
                               <a 
                                   href={getGoogleCalendarUrl(
                                       (() => {
                                           const d = new Date(startOfWeek);
                                           d.setDate(d.getDate() + (modal.sessionDay || 0));
                                           return d;
                                       })(), 
                                       modal.sessionTime,
                                       modal.isRecurring
                                   )}
                                   target="_blank"
                                   rel="noopener noreferrer"
                                   className="block w-full py-3 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-50 hover:border-gray-300 transition-colors flex items-center justify-center gap-2"
                               >
                                   <Calendar size={18} /> Agregar a Google Calendar
                               </a>
                               <a 
                                    href={getIcsUrl(
                                        (() => {
                                           const d = new Date(startOfWeek);
                                           d.setDate(d.getDate() + (modal.sessionDay || 0));
                                           return d;
                                       })(), 
                                       modal.sessionTime,
                                       modal.isRecurring
                                    )}
                                    download="entrenamiento_tommybox.ics"
                                    className="block w-full py-3 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl hover:bg-gray-50 hover:border-gray-300 transition-colors flex items-center justify-center gap-2"
                               >
                                    <Calendar size={18} /> Descargar .ICS
                               </a>
                               <button 
                                   onClick={() => setModal({ ...modal, type: 'none' })}
                                   className="block w-full py-3 bg-gray-900 text-white font-bold rounded-xl hover:bg-black mt-4"
                               >
                                   Cerrar
                               </button>
                           </div>
                       </div>
                   )}
               </div>
           </div>
       )}
    </section>
  );
};

export default AgendaView;

import React, { useState, useEffect, useMemo } from 'react';
import { Metric, Observation, Feeling, Session } from '../types';
import { mockDb } from '../services/mockData';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { BarChart2, List, TrendingUp } from 'lucide-react';

interface ClientHistoryProps {
  selectedClient: string | null;
  updateTrigger: string;
}

const ClientHistory: React.FC<ClientHistoryProps> = ({ selectedClient, updateTrigger }) => {
  const [metrics, setMetrics] = useState<Metric[]>([]);
  const [observations, setObservations] = useState<Observation[]>([]);
  const [feelings, setFeelings] = useState<Feeling[]>([]);
  const [sessions, setSessions] = useState<Session[]>([]);

  // View state for metrics
  const [metricsView, setMetricsView] = useState<'list' | 'chart'>('list');
  const [selectedExercise, setSelectedExercise] = useState<string>('');

  // Helper function to safely get milliseconds from timestamp objects that might be malformed
  const getTime = (t: any) => {
    if (!t) return 0;
    if (typeof t.toMillis === 'function') return t.toMillis();
    if (typeof t.toDate === 'function') return t.toDate().getTime();
    return 0;
  };

  useEffect(() => {
    if (selectedClient && mockDb[selectedClient]) {
      const clientData = mockDb[selectedClient];
      // Metrics: Newest first for list
      const sortedMetrics = Array.isArray(clientData.metrics) ? [...clientData.metrics].sort((a, b) => getTime(b.timestamp) - getTime(a.timestamp)) : [];
      setMetrics(sortedMetrics);

      // Default selected exercise to the most recent one if not set
      if (sortedMetrics.length > 0) {
          setSelectedExercise(sortedMetrics[0].exercise);
      }

      setObservations(Array.isArray(clientData.observations) ? [...clientData.observations].sort((a, b) => getTime(b.timestamp) - getTime(a.timestamp)) : []);
      setFeelings(Array.isArray(clientData.feelings) ? [...clientData.feelings].sort((a, b) => getTime(b.timestamp) - getTime(a.timestamp)) : []);
      setSessions(Array.isArray(clientData.sessions) ? [...clientData.sessions]
        .filter(s => new Date(s.date + 'T00:00:00') >= new Date(new Date().toDateString())) // only future sessions
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()) : []);
    } else {
      setMetrics([]);
      setObservations([]);
      setFeelings([]);
      setSessions([]);
    }
  }, [selectedClient, updateTrigger]);

  // Derived data for charts
  const uniqueExercises = useMemo(() => {
      const exercises = new Set(metrics.map(m => m.exercise));
      return Array.from(exercises);
  }, [metrics]);

  const chartData = useMemo(() => {
      if (!selectedExercise) return [];
      // Filter by exercise and sort Oldest -> Newest for chart
      return metrics
        .filter(m => m.exercise === selectedExercise)
        .sort((a, b) => getTime(a.timestamp) - getTime(b.timestamp))
        .map(m => ({
            date: new Date(m.date).toLocaleDateString('es-ES', { month: 'short', day: 'numeric' }),
            load: m.load,
            reps: m.reps,
            fullDate: m.date
        }));
  }, [metrics, selectedExercise]);

  return (
    <div>
      {!selectedClient ? (
        <div className="h-full flex items-center justify-center p-4">
          <p className="text-gray-500 text-center">Selecciona un cliente para ver el historial.</p>
        </div>
      ) : (
        <div className="max-h-[600px] overflow-y-auto space-y-6 pr-2 custom-scrollbar">

          {/* Sessions Section */}
          <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
            <h4 className="font-bold text-gray-800 mb-3 flex items-center gap-2 text-sm uppercase tracking-wide">
                Agendamiento
            </h4>
            {sessions.length > 0 ? (
              <ul className="space-y-2 text-sm text-gray-600">
                {sessions.map((s) => (
                    <li key={s.id} className="bg-white p-2 rounded-lg border border-gray-100 flex justify-between items-center">
                        <span className="font-semibold text-blue-600">{new Date(s.date).toLocaleDateString('es-ES', { timeZone: 'UTC', weekday: 'short', day: 'numeric' })}</span>
                        <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs">{s.time}</span>
                    </li>
                ))}
              </ul>
            ) : <p className="text-gray-500 text-sm italic">No hay sesiones próximas agendadas.</p>}
          </div>

          {/* Metrics Section */}
          <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
            <div className="flex justify-between items-center mb-4">
                <h4 className="font-bold text-gray-800 flex items-center gap-2 text-sm uppercase tracking-wide">
                    Métricas de Fuerza
                </h4>
                {metrics.length > 0 && (
                    <div className="flex bg-gray-100 p-1 rounded-lg">
                        <button 
                            onClick={() => setMetricsView('list')}
                            className={`p-1.5 rounded-md transition-all ${metricsView === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                            title="Ver Lista"
                        >
                            <List size={16} />
                        </button>
                        <button 
                            onClick={() => setMetricsView('chart')}
                            className={`p-1.5 rounded-md transition-all ${metricsView === 'chart' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
                            title="Ver Gráfico"
                        >
                            <BarChart2 size={16} />
                        </button>
                    </div>
                )}
            </div>

            {metrics.length > 0 ? (
              <>
                  {metricsView === 'list' ? (
                    <ul className="space-y-2 text-sm text-gray-600">
                        {metrics.map((m) => (
                            <li key={m.id} className="flex justify-between items-center border-b border-gray-50 last:border-0 pb-2 last:pb-0">
                                <span className="font-bold text-gray-800">{m.exercise}</span>
                                <div className="text-right">
                                    <span className="text-xs font-mono bg-blue-50 text-blue-700 px-1.5 py-0.5 rounded mr-2">{m.load}kg x {m.reps}</span>
                                    <span className="text-[10px] text-gray-400">{new Date(m.date).toLocaleDateString('es-ES', {month:'numeric', day:'numeric'})}</span>
                                </div>
                            </li>
                        ))}
                    </ul>
                  ) : (
                    <div className="animate-fade-in">
                        <div className="mb-4">
                            <select 
                                value={selectedExercise} 
                                onChange={(e) => setSelectedExercise(e.target.value)}
                                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-lg text-sm font-medium focus:ring-2 focus:ring-blue-100 outline-none"
                            >
                                {uniqueExercises.map(ex => (
                                    <option key={ex} value={ex}>{ex}</option>
                                ))}
                            </select>
                        </div>

                        {chartData.length > 0 ? (
                            <div className="h-[200px] w-full">
                                <ResponsiveContainer width="100%" height="100%">
                                    <LineChart data={chartData}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                                        <XAxis 
                                            dataKey="date" 
                                            axisLine={false} 
                                            tickLine={false} 
                                            tick={{fontSize: 10, fill: '#9ca3af'}} 
                                            dy={5} 
                                            interval="preserveStartEnd"
