import React, { useState, useEffect, Suspense } from 'react';
import { User } from 'firebase/auth'; // Keep type for compatibility
import { View, UserProfile, GamificationProfile } from './types';
import { views } from './constants';
import { mockTrainer, mockUsers, addUser, updateUserPlan, cleanOldTrackers, completeUserProfile, checkAndApplyBirthdayBonus, updateUserProfile as updateUserProfileService } from './services/mockData';

import NavMenu from './components/NavMenu';
import HomeView from './components/views/HomeView';
import PlansView from './components/views/PlansView';
import LoginView from './components/views/LoginView';
import DashboardView from './components/views/DashboardView';
import ChatView from './components/ChatView';
import RewardNotification from './components/RewardNotification';
import ProfileView from './components/views/ProfileView';
import { Loader2 } from 'lucide-react';

// Lazy Load heavy components for performance (Code Splitting)
const AgendaView = React.lazy(() => import('./components/views/AgendaView'));
const AchievementsView = React.lazy(() => import('./components/views/AchievementsView'));
const TrainerDashboardView = React.lazy(() => import('./components/views/TrainerDashboardView'));
const RewardsStoreView = React.lazy(() => import('./components/views/RewardsStoreView'));

const createDefaultGamificationProfile = (userId: string): GamificationProfile => ({
    userId: userId,
    totalPoints: 0,
    level: 1,
    experience: 0,
    experienceToNextLevel: 100, // Points for level 2
    badges: [],
    achievements: [],
    streaks: [
        { type: 'training', current: 0, best: 0, lastUpdate: { toDate: () => new Date(0) } as any }
    ],
});

// Loading Spinner for Suspense
const LoadingSpinner = () => (
    <div className="flex h-[50vh] w-full items-center justify-center">
        <Loader2 className="animate-spin text-blue-600" size={48} />
    </div>
);

// Main App Component
const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(views.HOME);
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(false);
  const [isTrainer, setIsTrainer] = useState<boolean>(false);
  const [user, setUser] = useState<(UserProfile & { id: string }) | null>(null);
  const [chatCompanionId, setChatCompanionId] = useState<string | null>(null);
  const [showChat, setShowChat] = useState<boolean>(false);
  const [selectedPlan, setSelectedPlan] = useState<string | null>(null);
  const [rewardQueue, setRewardQueue] = useState<any[]>([]);
  const [currentNotification, setCurrentNotification] = useState<any>(null);
  const [pendingCompletionUser, setPendingCompletionUser] = useState<(UserProfile & { id: string }) | null>(null);

  // Logout Modal State
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  // Chat State shared between views
  const [selectedClientForChat, setSelectedClientForChat] = useState<string|null>(null);

  const trainerId = mockTrainer.id;

  useEffect(() => {
    cleanOldTrackers();
  }, []);

  useEffect(() => {
    if (rewardQueue.length > 0 && !currentNotification) {
      const nextReward = rewardQueue[0];
      setCurrentNotification(nextReward);
      setRewardQueue(q => q.slice(1));
    }
  }, [rewardQueue, currentNotification]);

  const handleLogin = ({ usernameOrEmail, password }: { usernameOrEmail: string, password: string }) => {
    // Case insensitive username/email check
    const inputLogin = usernameOrEmail.toLowerCase().trim();

    const foundUser = mockUsers.find(u => 
        u.email.toLowerCase() === inputLogin || 
        u.username.toLowerCase() === inputLogin
    );

    // Password remains case-sensitive
    if (foundUser && foundUser.password === password) {
        if (!foundUser.registrationCompleted) {
            setPendingCompletionUser(foundUser);
            setCurrentView(views.LOGIN); 
            return; 
        }
        setUser(foundUser);
        setIsLoggedIn(true);
        setIsTrainer(foundUser.isTrainer);
        setCurrentView(views.DASHBOARD);
        const birthdayRewards = checkAndApplyBirthdayBonus(foundUser.id);
        if (birthdayRewards) {
            setRewardQueue(q => [...q, birthdayRewards]);
        }
    } else {
        throw new Error("Credenciales inválidas.");
    }
  };

  const handleRegister = ({ email, password }: { email: string, password: string }): UserProfile & { id: string } => {
      const existingUser = mockUsers.find(u => u.email.toLowerCase() === email.toLowerCase());
      if (existingUser) {
          throw new Error("El email ya está registrado. Por favor, inicia sesión.");
      }

      const newUserId = `client${Date.now()}`;
      const newUser: UserProfile & { id: string } = {
          id: newUserId,
          email: email,
          username: email.split('@')[0],
          displayName: email.split('@')[0],
          password: password,
          plan: selectedPlan || undefined,
          isTrainer: false,
          createdAt: { toDate: () => new Date() } as any,
          gamification: createDefaultGamificationProfile(newUserId),
          registrationCompleted: false,
      };

      addUser(newUser);
      setSelectedPlan(null);
      return newUser;
  };

  const completeRegistration = (userToComplete: UserProfile & { id: string }, additionalData: { displayName: string; birthDate: string }) => {
      completeUserProfile(userToComplete.id, additionalData);
      const updatedUser = mockUsers.find(u => u.id === userToComplete.id);
      if (updatedUser) {
          setUser(updatedUser);
          setIsLoggedIn(true);
          setIsTrainer(false);
          setCurrentView(views.DASHBOARD);
          setPendingCompletionUser(null);
          alert(`¡Bienvenido a TommyBox, ${additionalData.displayName}! 🎉`);
      }
  };

  // Trigger the logout confirmation modal
  const requestLogout = () => {
      setShowLogoutConfirm(true);
  };

  // Actual Logout Logic
  const executeLogout = () => {
    setShowLogoutConfirm(false);
    // Aggressive reset of all states
    setChatCompanionId(null);
    setShowChat(false);
    setPendingCompletionUser(null);
    setUser(null);
    setIsTrainer(false);
    setIsLoggedIn(false);
    setCurrentView(views.HOME);

    // Optional: clear any ephemeral states if necessary
    window.scrollTo(0, 0);
  };

  const handleOpenChat = () => {
      if (isTrainer && selectedClientForChat) {
          setChatCompanionId(selectedClientForChat);
          setShowChat(true);
      } else if (!isTrainer && trainerId) {
          setChatCompanionId(trainerId);
          setShowChat(true);
      }
  };

  const handlePlanSelect = (planName: string) => {
    if (isLoggedIn && user) {
        updateUserPlan(user.id, planName);
        setUser({ ...user, plan: { ...user.plan, name: planName } as any });
        alert(`¡Plan "${planName}" seleccionado!`);
        setCurrentView(views.DASHBOARD);
    } else {
        setSelectedPlan(planName);
        setCurrentView(views.LOGIN);
    }
  };

  const handleUpdateProfile = (updatedData: Partial<UserProfile>) => {
    if (!user) return;
    const updatedUser = updateUserProfileService(user.id, updatedData);
    if (updatedUser) {
        setUser(updatedUser);
        alert("Perfil actualizado con éxito.");
        setCurrentView(views.DASHBOARD);
    } else {
        alert("Error al actualizar el perfil.");
    }
  };

  const renderView = () => {
    switch (currentView) {
      case views.HOME:
        return <HomeView setCurrentView={setCurrentView} />;
      case views.PLANS:
        return <PlansView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handlePlanSelect={handlePlanSelect} isTrainer={isTrainer} />;
      case views.AGENDA:
        return (
            <Suspense fallback={<LoadingSpinner />}>
                <AgendaView userId={user?.id} userPlan={user?.plan} setRewardQueue={setRewardQueue} setCurrentView={setCurrentView} isTrainer={isTrainer} />
            </Suspense>
        );
      case views.ACHIEVEMENTS:
        return (
            <Suspense fallback={<LoadingSpinner />}>
                <AchievementsView />
            </Suspense>
        );
      case views.LOGIN:
        return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
      case views.REWARDS_STORE:
        if (!isLoggedIn || !user) return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
        return (
            <Suspense fallback={<LoadingSpinner />}>
                <RewardsStoreView user={user} setCurrentView={setCurrentView} />
            </Suspense>
        );
      case views.DASHBOARD:
        if (!isLoggedIn || !user) return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
        return isTrainer ? (
             <Suspense fallback={<LoadingSpinner />}>
                 <TrainerDashboardView 
                    setChatCompanionId={setChatCompanionId} 
                    setShowChat={setShowChat} 
                    setSelectedClientForChat={setSelectedClientForChat}
                    handleLogout={requestLogout}
                />
             </Suspense>
        ) : (
            <DashboardView 
                trainerId={trainerId} 
                user={user as any} 
                setChatCompanionId={setChatCompanionId} 
                setShowChat={setShowChat} 
                setCurrentView={setCurrentView}
                setRewardQueue={setRewardQueue}
            />
        );
      case views.CHAT:
        return null; // Handled by overlay
      case views.PROFILE:
        if (!isLoggedIn || !user) return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
        return <ProfileView user={user} onUpdateProfile={handleUpdateProfile} setCurrentView={setCurrentView} />;
      default:
        return <HomeView setCurrentView={setCurrentView} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-gray-900 font-sans">
      <main className="flex-1 overflow-y-auto pb-20 md:pb-0 custom-scrollbar">
        {renderView()}
      </main>

      {/* NavMenu */}
      <div className="fixed bottom-0 left-0 w-full h-20 bg-white shadow-lg border-t border-gray-100 z-40 md:sticky md:top-0 md:h-20">
        <NavMenu 
            currentView={currentView} 
            setCurrentView={setCurrentView} 
            isLoggedIn={isLoggedIn} 
            handleLogout={requestLogout} 
        />
      </div>

      {/* Chat Overlay */}
      {showChat && user && chatCompanionId && (
        <ChatView 
            userId={user.id} 
            companionId={chatCompanionId} 
            onClose={() => setShowChat(false)} 
        />
      )}

      {/* Reward Notification */}
      {currentNotification && (
          <RewardNotification 
              reward={currentNotification} 
              onDismiss={() => setCurrentNotification(null)} 
          />
      )}

      {/* Logout Confirmation Modal */}
      {showLogoutConfirm && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl">
                <h3 className="text-xl font-bold text-gray-900 mb-2">¿Cerrar Sesión?</h3>
                <p className="text-gray-500 mb-6">Tendrás que volver a ingresar tus credenciales para acceder.</p>
                <div className="flex gap-3">
                    <button 
                        onClick={() => setShowLogoutConfirm(false)}
                        className="flex-1 py-3 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200 transition-colors"
                    >
                        Cancelar
                    </button>
                    <button 
                        onClick={executeLogout}
                        className="flex-1 py-3 bg-red-600 text-white font-bold rounded-xl hover:bg-red-700 transition-colors"
                    >
                        Salir
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { X, Send, Bot, User, Loader2 } from 'lucide-react';
import { mockChatMessages, mockUsers, addChatMessage, mockDb } from '../services/mockData';
import { GoogleGenAI } from "@google/genai";

interface ChatViewProps {
  userId: string;
  companionId: string;
  onClose: () => void;
}

const ChatView: React.FC<ChatViewProps> = ({ userId, companionId, onClose }) => {
  const sortedIds = [userId, companionId].sort();
  const chatId = `${sortedIds[0]}_${sortedIds[1]}`;

  const [messages, setMessages] = useState<any[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Identify who is who
  const currentUserIsTrainer = userId.includes('trainer'); // Simple check based on ID convention in mockData
  const companionUser = mockUsers.find(u => u.id === companionId);
  const companionName = companionUser?.displayName || companionUser?.username || 'Chat';

  useEffect(() => {
    // Load existing messages
    if (mockChatMessages[chatId]) {
        setMessages(mockChatMessages[chatId]);
    }
  }, [chatId]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  // --- RAG: RETRIEVAL AUGMENTED GENERATION ---
  // If the companion is the "Trainer" (AI), we gather context about the user (userId)
  const getUserContext = () => {
      const userProfile = mockUsers.find(u => u.id === userId);
      const userData = mockDb[userId];

      if (!userProfile || !userData) return '';

      const recentMetrics = userData.metrics?.slice(-3).map(m => 
          `- ${m.exercise}: ${m.load}kg x ${m.reps} (RPE: ${m.rpe || 'N/A'}) el ${m.date}`
      ).join('\n') || 'Sin registros recientes.';

      const recentSessions = userData.sessions?.filter(s => new Date(s.date) > new Date()).slice(0, 2).map(s =>
          `- ${s.date} a las ${s.time}`
      ).join('\n') || 'No hay sesiones futuras agendadas.';

      const level = userProfile.gamification?.level || 1;
      const plan = userProfile.plan || 'Sin plan';

      return `
      CONTEXTO DEL ATLETA:
      - Nombre: ${userProfile.displayName || userProfile.username}
      - Nivel: ${level}
      - Plan: ${plan}
      - Últimos registros de fuerza:
      ${recentMetrics}
      - Próximas sesiones agendadas:
      ${recentSessions}
      `;
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim()) return;

    const userMsg = {
        id: `msg_${Date.now()}`,
        senderId: userId,
        text: newMessage,
        timestamp: { toDate: () => new Date() }
    };

    // Optimistic Update
    const updatedMessages = [...messages, userMsg];
    setMessages(updatedMessages);
    addChatMessage(chatId, userMsg);
    setNewMessage('');

    // AI LOGIC
    // Only trigger AI if the companion is the Trainer and the user is a Client
    if (companionId === 'trainer01' && !currentUserIsTrainer) {
        setIsTyping(true);
        try {
            // RAG Injection
            const userContext = getUserContext();

            const systemInstruction = `
            Eres Tommy, un entrenador personal experto, motivador y conciso de la app TommyBox.
            Tu objetivo es ayudar al atleta a mejorar su rendimiento, resolver dudas sobre ejercicios y mantener la motivación alta.
            Usa emojis ocasionalmente. Sé breve.

            ${userContext}

            Responde basándote en el contexto del atleta si es relevante.
            `;

            // Initialize Gemini
            // NOTE: In a real app, do not expose API_KEY in frontend code. 
            // Use a backend proxy. For this demo, we assume process.env.API_KEY is injected by the bundler.
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Construct history for Gemini
            // Map our chat structure to Gemini's content structure
            // We take the last 10 messages to save tokens
            const history = updatedMessages.slice(-10).map(m => ({
                role: m.senderId === 'trainer01' ? 'model' : 'user',
                parts: [{ text: m.text }]
            }));

            const chat = ai.chats.create({
                model: 'gemini-2.5-flash',
                config: {
                    systemInstruction: systemInstruction,
                },
                history: history
            });

            const result = await chat.sendMessage({ message: newMessage });
            const aiResponseText = result.text;

            const aiMsg = {
                id: `msg_${Date.now() + 1}`,
                senderId: companionId,
                text: aiResponseText,
                timestamp: { toDate: () => new Date() }
            };

            setMessages(prev => [...prev, aiMsg]);
            addChatMessage(chatId, aiMsg);

        } catch (error) {
            console.error("AI Error:", error);
            // Fallback message if AI fails
            const errorMsg = {
                id: `msg_${Date.now() + 1}`,
                senderId: companionId,
                text: "Lo siento, estoy teniendo problemas de conexión en este momento. Intenta de nuevo más tarde.",
                timestamp: { toDate: () => new Date() }
            };
            setMessages(prev => [...prev, errorMsg]);
        } finally {
            setIsTyping(false);
        }
    }
  };

  return (
    <div className="fixed bottom-0 right-0 md:bottom-24 md:right-6 w-full md:w-96 h-[80vh] md:h-[600px] bg-white md:rounded-2xl shadow-2xl flex flex-col overflow-hidden z-50 border border-gray-200 animate-slide-up">
      {/* Header */}
      <div className="p-4 bg-gray-900 text-white flex justify-between items-center shrink-0">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center">
                {companionId === 'trainer01' ? <Bot size={20} /> : <User size={20} />}
            </div>
            <div>
                <h3 className="font-bold text-sm">{companionName}</h3>
                <div className="flex items-center gap-1.5">
                    <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
                    <span className="text-xs text-gray-300">En línea</span>
                </div>
            </div>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <X size={20} />
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
        {messages.map((msg) => {
            const isMe = msg.senderId === userId;
            return (
                <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] rounded-2xl p-3 text-sm leading-relaxed shadow-sm ${
                        isMe 
                        ? 'bg-blue-600 text-white rounded-br-none' 
                        : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
                    }`}>
                        {msg.text}
                        <p className={`text-[10px] mt-1 text-right ${isMe ? 'text-blue-200' : 'text-gray-400'}`}>
                            {new Date(typeof msg.timestamp.toDate === 'function' ? msg.timestamp.toDate() : msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                        </p>
                    </div>
                </div>
            );
        })}
        {isTyping && (
             <div className="flex justify-start">
                <div className="bg-white border border-gray-100 rounded-2xl p-3 rounded-bl-none shadow-sm flex items-center gap-2">
                    <Loader2 size={16} className="animate-spin text-gray-400" />
                    <span className="text-xs text-gray-400">Tommy está escribiendo...</span>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <form onSubmit={handleSendMessage} className="p-4 bg-white border-t border-gray-100 shrink-0">
        <div className="flex gap-2">
            <input 
                type="text" 
                value={newMessage}
                onChange={(e) => setNewMessage(e.target.value)}
                placeholder="Escribe un mensaje..." 
                className="flex-1 px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            />
            <button 
                type="submit" 
                disabled={!newMessage.trim() || isTyping}
                className="p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-md"
            >
                <Send size={20} />
            </button>
        </div>
      </form>
    </div>
  );
};

