// Robust Direct Camera Scanner
const DirectScannerOverlay: React.FC<{ onClose: () => void; onScan: (decodedText: string) => void }> = ({ onClose, onScan }) => {
    const scannerId = useRef(`scanner-${Math.random().toString(36).substr(2, 9)}`).current;
    const scannerRef = useRef<Html5Qrcode | null>(null);
    const isScanningRef = useRef(false);

    useEffect(() => {
        let mounted = true;

        const startScanner = async () => {
            const element = document.getElementById(scannerId);
            if (!element) return;
            if (scannerRef.current) return;

            try {
                const html5QrCode = new Html5Qrcode(scannerId);
                scannerRef.current = html5QrCode;

                await html5QrCode.start(
                    { facingMode: "environment" },
                    { 
                        fps: 10, 
                        qrbox: { width: 250, height: 250 },
                        aspectRatio: window.innerWidth / window.innerHeight
                    },
                    (decodedText) => {
                         if (mounted) onScan(decodedText);
                    },
                    (errorMessage) => { /* scanning... */ }
                );
                isScanningRef.current = true;
            } catch (err) {
                console.error("Scanner start failed", err);
            }
        };

        const timer = setTimeout(startScanner, 300); // Slight delay for DOM stability

        return () => {
            mounted = false;
            clearTimeout(timer);
            if (scannerRef.current && isScanningRef.current) {
                scannerRef.current.stop().then(() => {
                    if (scannerRef.current) scannerRef.current.clear();
                    isScanningRef.current = false;
                }).catch(err => console.warn("Stop failed", err));
            }
        };
    }, [onScan, scannerId]);

    return (
        <div className="fixed inset-0 z-[100] bg-black">
            {/* 1. Camera Feed Container - Absolute Background */}
            <div id={scannerId} className="absolute inset-0 w-full h-full bg-black"></div>

            {/* 2. Semi-transparent Overlay to dim surrounding area */}
            <div className="absolute inset-0 bg-black/30 pointer-events-none z-10"></div>

            {/* 3. The Scanning Window - Clear and Unobstructed */}
            <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center z-20">
                <div className="relative w-72 h-72">
                    {/* Visual Frame Corners */}
                    <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-blue-500 rounded-tl-3xl"></div>
                    <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-blue-500 rounded-tr-3xl"></div>
                    <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-blue-500 rounded-bl-3xl"></div>
                    <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-blue-500 rounded-br-3xl"></div>

                    {/* Scanning Laser Animation */}
                    <div className="absolute top-0 left-0 w-full h-1 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,1)] animate-[scan_2s_infinite]"></div>

                    {/* Clear center */}
                    <div className="w-full h-full border border-blue-400/30 bg-transparent box-border rounded-xl"></div>
                </div>

                <div className="mt-8 bg-black/60 backdrop-blur-md px-6 py-3 rounded-full border border-white/10">
                    <p className="text-white font-medium text-sm">Apunta al código del atleta</p>
                </div>
            </div>

            {/* 4. Close Button - Interactive */}
            <button 
                onClick={onClose} 
                className="absolute top-6 right-6 p-4 bg-white/10 backdrop-blur-md rounded-full text-white hover:bg-white/20 transition-all z-50 pointer-events-auto border border-white/10"
            >
                <X size={28} />
            </button>

            {/* Force video element to fill container */}
            <style>{`
                #${scannerId} video {
                    object-fit: cover !important;
                    width: 100% !important;
                    height: 100% !important;
                }
                @keyframes scan {
                    0% { top: 0; opacity: 0; }
                    50% { opacity: 1; }
                    100% { top: 100%; opacity: 0; }
                }
            `}</style>
        </div>
    );
};

const TrainerDashboardView: React.FC<TrainerDashboardViewProps> = ({ setChatCompanionId, setShowChat, setSelectedClientForChat, handleLogout }) => {
    // State
    const [clients, setClients] = useState<(UserProfile & {id: string})[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedClientId, setSelectedClientId] = useState<string | null>(null);

    // UI State
    const [sidebarTab, setSidebarTab] = useState<'clients' | 'inbox'>('clients');
    const [detailTab, setDetailTab] = useState<'log' | 'history'>('log');
    const [showScanner, setShowScanner] = useState(false);
    const [feedbackMsg, setFeedbackMsg] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const [viewMode, setViewMode] = useState<'list' | 'detail'>('list'); // Master-Detail controller

    const feedbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Data State
    const [pendingAchievements, setPendingAchievements] = useState<any[]>([]);
    const [notifications, setNotifications] = useState<any[]>([]);
    const [formData, setFormData] = useState({ exercise: '', load: '', reps: '', rpe: '', observation: '' });

    useEffect(() => {
        return () => {
            if (feedbackTimerRef.current) clearTimeout(feedbackTimerRef.current);
        };
    }, []);

    useEffect(() => {
        setClients(mockUsers.filter(user => !user.isTrainer));
        setPendingAchievements(mockPendingAchievements);

        const trainerData = mockDb['trainer01'];
        if (trainerData && (trainerData as any).notifications) {
            setNotifications([...(trainerData as any).notifications].reverse());
        }
    }, []);

    useEffect(() => {
        setSelectedClientForChat(selectedClientId);
    }, [selectedClientId, setSelectedClientForChat]);

    const filteredClients = useMemo(() => {
        return clients.filter(c => 
            (c.displayName || c.username || '').toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [clients, searchTerm]);

    const selectedClient = useMemo(() => 
        clients.find(c => c.id === selectedClientId), 
    [clients, selectedClientId]);

    // Actions
    const handleSelectClient = (id: string) => {
        setSelectedClientId(id);
        setViewMode('detail'); // Force switch to detail on mobile
        // On desktop this state is ignored by CSS media queries or we can use it to highlight
    };

    const handleBackToList = () => {
        setViewMode('list');
        // Optional: clear selection? 
        // setSelectedClientId(null); 
    };

    const showFeedback = (type: 'success' | 'error', text: string) => {
        if (feedbackTimerRef.current) clearTimeout(feedbackTimerRef.current);
        setFeedbackMsg({ type, text });
        feedbackTimerRef.current = setTimeout(() => setFeedbackMsg(null), 3000);
    };

    const handleSave = () => {
        if (!selectedClientId) return;
        const { exercise, load, reps, rpe, observation } = formData;

        if (!exercise && !observation) {
            showFeedback('error', 'Ingresa una métrica o una observación.');
            return;
        }

        if (exercise) {
             addMetric(selectedClientId, {
                id: `m_${Date.now()}`,
                exercise,
                load: Number(load),
                reps: Number(reps),
                rpe: rpe ? Number(rpe) : undefined,
                date: new Date().toISOString().split('T')[0],
                timestamp: mockTimestamp(new Date())
            });
        }

        if (observation) {
             addObservation(selectedClientId, {
                id: `o_${Date.now()}`,
                comment: observation,
                date: new Date().toISOString().split('T')[0],
                timestamp: mockTimestamp(new Date())
            });
        }

        showFeedback('success', 'Datos guardados correctamente.');
        setFormData({ exercise: '', load: '', reps: '', rpe: '', observation: '' });
        setDetailTab('history'); 
    };

    const handleAchievementAction = (action: 'approve' | 'reject', id: string) => {
        if (action === 'approve') {
            approvePendingAchievement(id);
            showFeedback('success', 'Logro aprobado.');
        } else {
            rejectPendingAchievement(id);
            showFeedback('success', 'Logro rechazado.');
        }
        setPendingAchievements(prev => prev.filter(p => p.id !== id));
    };

    const handleQrScan = useCallback((decodedText: string) => {
        setShowScanner(false);

        if (decodedText === "TOMMYBOX_CHECKIN_2025") {
             showFeedback('success', 'Código de gimnasio detectado.');
             return;
        } 

        const foundClient = mockUsers.find(c => c.id === decodedText && !c.isTrainer);

        if (foundClient) {
            setSelectedClientId(foundClient.id);
            setViewMode('detail');
            setSidebarTab('clients'); 
            showFeedback('success', `Atleta identificado: ${foundClient.displayName || foundClient.username}`);
